#include<bits/stdc++.h>
using namespace std;
string s,ss="0123456789ABCDEF",aa;
int x,n,a;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>x>>s>>n;
	int l=s.size()-1;
	for(int i=0; i<s.size(); i++) {
		int v;
		if(isupper(s[i]))v=s[i]-'A'+10;
		else v=s[i]-'0';
		a+=v*pow(x,l);
		l--;
	}
	while(a!=0){
		aa=ss[a%n]+aa;
		a/=n;
	}
	cout<<aa;
	return 0;
}
